module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;
    reg [7:0] temp_data;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'b0000;
            temp_data <= 8'b0;
            dout_parallel <= 8'b0;
            dout_valid <= 1'b0;
        end
        else if (din_valid) begin
            temp_data <= {temp_data[6:0], din_serial};
            cnt <= cnt + 4'b0001;
            if (cnt == 4'b1000) begin
                dout_parallel <= temp_data;
                dout_valid <= 1'b1;
            end
            else begin
                dout_valid <= 1'b0;
            end
        end
    end
endmodule

module width_8to16 (
    input 				   clk,
    input 				   rst_n,
    input				      valid_in,
    input	   [7:0]		   data_in,
    output	reg			valid_out,
    output   reg [15:0]	data_out
);

reg [7:0] data_lock;
reg flag;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 16'b0;
        valid_out <= 1'b0;
        flag <= 1'b0;
    end
    else begin
        if (valid_in) begin
            if (flag) begin
                data_out <= {data_lock, data_in};
                valid_out <= 1'b1;
                flag <= 1'b0;
            end
            else begin
                data_lock <= data_in;
                flag <= 1'b1;
                valid_out <= 1'b0;
            end
        end
        else begin
            valid_out <= 1'b0;
        end
    end
end

endmodule

module sub_64bit (
    input [63:0] A,
    input [63:0] B,
    output reg [63:0] result,
    output reg overflow
);

    always @(*) begin
        {overflow, result} = A - B;
        if ((A[63] == 0 && B[63] == 1 && result[63] == 1) || (A[63] == 1 && B[63] == 0 && result[63] == 0)) begin
            overflow = 1'b1;
        end else begin
            overflow = 1'b0;
        end
    end

endmodule

module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
); 
    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
            p_red <= 0;
            p_yellow <= 0;
            p_green <= 0;
        end else begin
            case(state)
                idle: begin
                    state <= s1_red;
                    p_red <= 0;
                    p_yellow <= 0;
                    p_green <= 0;
                end
                s1_red: begin
                    if (cnt == 3) begin
                        state <= s3_green;
                        p_red <= 0;
                        p_yellow <= 0;
                        p_green <= 1;
                    end else begin
                        state <= s1_red;
                        p_red <= 1;
                        p_yellow <= 0;
                        p_green <= 0;
                    end
                end
                s2_yellow: begin
                    if (cnt == 3) begin
                        state <= s1_red;
                        p_red <= 1;
                        p_yellow <= 0;
                        p_green <= 0;
                    end else begin
                        state <= s2_yellow;
                        p_red <= 0;
                        p_yellow <= 1;
                        p_green <= 0;
                    end
                end
                s3_green: begin
                    if (cnt == 3) begin
                        state <= s2_yellow;
                        p_red <= 0;
                        p_yellow <= 1;
                        p_green <= 0;
                    end else begin
                        state <= s3_green;
                        p_red <= 0;
                        p_yellow <= 0;
                        p_green <= 1;
                    end
                end
            endcase
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 10;
        end else begin
            if (pass_request && green && (cnt > 10)) begin
                cnt <= 10;
            end else if (!green && p_green) begin
                cnt <= 60;
            end else if (!yellow && p_yellow) begin
                cnt <= 5;
            end else if (!red && p_red) begin
                cnt <= 10;
            end else begin
                cnt <= cnt - 1;
            end
        end
    end

    assign clock = cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            yellow <= 0;
            green <= 0;
        end else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule

