module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output reg [31:0] yout,
    output reg done
); 
    integer i;
    reg [15:0] areg;
    reg [15:0] breg;
    reg [31:0] yout_r;
    reg done_r;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            i <= 0;
        end else begin
            if (start && i < 17) begin
                i <= i + 1;
            end else begin
                i <= 0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            done_r <= 0;
        end else begin
            if (i == 16) begin
                done_r <= 1;
            end else if (i == 17) begin
                done_r <= 0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            areg <= 0;
            breg <= 0;
            yout_r <= 0;
        end else begin
            if (start) begin
                if (i == 0) begin
                    areg <= ain;
                    breg <= bin;
                end else if (i > 0 && i < 17) begin
                    if (areg[i-1]) begin
                        yout_r <= yout_r + (breg << (i-1));
                    end
                end
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            done <= 0;
        end else begin
            done <= done_r;
        end
    end

    assign yout = yout_r;
endmodule

module freq_divbyfrac #(
    parameter MUL2_DIV_CLK = 7
) (
    input               rst_n,
    input               clk,
    output              clk_div
);
parameter DIV_CLK = MUL2_DIV_CLK / 2;
parameter MUL2_DIV_CLK_WIDTH = $clog2(MUL2_DIV_CLK);
reg [MUL2_DIV_CLK_WIDTH-1:0] cnt;
reg clk_div_even;
reg clk_div_even_d;
reg clk_div_odd;
reg clk_div_odd_d;
wire clk_div_even_tmp;
wire clk_div_odd_tmp;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 0;
        clk_div_even <= 1'b0;
        clk_div_even_d <= 1'b0;
        clk_div_odd <= 1'b1;
        clk_div_odd_d <= 1'b0;
    end else begin
        if (cnt == MUL2_DIV_CLK - 1) begin
            cnt <= 0;
            clk_div_even <= ~clk_div_even;
            clk_div_even_d <= clk_div_even;
            clk_div_odd <= ~clk_div_odd;
            clk_div_odd_d <= clk_div_odd;
        end else begin
            cnt <= cnt + 1;
        end
    end
end
assign clk_div_even_tmp = clk_div_even & ~clk_div_even_d;
assign clk_div_odd_tmp = clk_div_odd & ~clk_div_odd_d;
assign clk_div = clk_div_even_tmp | clk_div_odd_tmp;
endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output reg valid_out,
    output reg dout
); 
    reg [3:0] data;
    reg [1:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            data <= 4'b0;
            cnt <= 2'b0;
            valid_out <= 1'b0;
        end else begin
            if (cnt == 2'b11) begin
                data <= d;
                cnt <= 2'b0;
                valid_out <= 1'b1;
            end else begin
                cnt <= cnt + 1;
                valid_out <= 1'b0;
                data <= {data[2:0], data[3]};
            end
        end
    end

    assign dout = data[3];
endmodule

module float_multi (
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

reg [2:0] counter;
reg [23:0] a_mantissa, b_mantissa, z_mantissa;
reg [9:0] a_exponent, b_exponent, z_exponent;
reg a_sign, b_sign, z_sign;
reg [49:0] product;
reg guard_bit, round_bit, sticky;

always @(posedge clk) begin
    if (rst) begin
        counter <= 0;
        a_mantissa <= 0;
        b_mantissa <= 0;
        z_mantissa <= 0;
        a_exponent <= 0;
        b_exponent <= 0;
        z_exponent <= 0;
        a_sign <= 0;
        b_sign <= 0;
        z_sign <= 0;
        product <= 0;
        guard_bit <= 0;
        round_bit <= 0;
        sticky <= 0;
        z <= 0;
    end else begin
        case (counter)
            0: begin
                a_mantissa <= {1'b1, a[22:0]};
                b_mantissa <= {1'b1, b[22:0]};
                a_exponent <= a[30:23] - 127;
                b_exponent <= b[30:23] - 127;
                a_sign <= a[31];
                b_sign <= b[31];
                counter <= 1;
            end
            1: begin
                if ((a_exponent == 128 && a_mantissa != 0) || (b_exponent == 128 && b_mantissa != 0)) begin
                    z <= 255;
                    counter <= 2;
                end else begin
                    if (a_exponent == 0 || b_exponent == 0) begin
                        z <= 0;
                        counter <= 2;
                    end else begin
                        z_sign <= a_sign ^ b_sign;
                        product <= a_mantissa * b_mantissa;
                        counter <= 2;
                    end
                end
            end
            2: begin
                if (product[49]) begin
                    z_mantissa <= product[48:25];
                    z_exponent <= a_exponent + b_exponent;
                end else begin
                    z_mantissa <= product[47:24];
                    z_exponent <= a_exponent + b_exponent - 1;
                end
                counter <= 3;
            end
            3: begin
                guard_bit <= product[24];
                round_bit <= product[23];
                sticky <= |product[22:0];
                counter <= 4;
            end
            4: begin
                if (guard_bit && (round_bit || sticky)) begin
                    z_mantissa <= z_mantissa + 1;
                    if (z_mantissa == 256) begin
                        z_exponent <= z_exponent + 1;
                        if (z_exponent == 255) begin
                            z <= 255;
                        end
                    end
                end
                counter <= 5;
            end
            5: begin
                if (z_exponent == 0) begin
                    z <= 0;
                end else begin
                    z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                end
                counter <= 0;
            end
        endcase
    end
end

endmodule

module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

reg [15:0] a_reg;
reg [7:0] b_reg;
reg [15:0] remainder;
reg [4:0] i;

always @(A, B) begin
    a_reg <= A;
    b_reg <= B;
end

always @(a_reg, b_reg) begin
    result = 0;
    remainder = a_reg;
    for (i = 16; i > 0; i = i - 1) begin
        if (remainder[15:8] >= b_reg) begin
            result[i-1] = 1;
            remainder = remainder - {1'b0, b_reg, 7'b0};
        end else begin
            result[i-1] = 0;
        end
        remainder = {remainder[14:0], a_reg[i-1]};
    end
    odd = remainder;
end

endmodule

module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    integer i;

    always @(*) begin
        partial_product = 0;
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                partial_product = partial_product + (A << i);
            end
        end
        product = partial_product;
    end

endmodule

module multi_booth_8bit (
    output reg [15:0] p,
    output reg rdy,
    input clk,
    input reset,
    input [7:0] a,
    input [7:0] b
);
    reg [15:0] multiplier;
    reg [15:0] multiplicand;
    reg [4:0] ctr;

    always @(posedge clk or posedge (reset)) begin
        if (reset) begin
            multiplier <= {{8{a[7]}}, a};
            multiplicand <= {{8{b[7]}}, b};
            ctr <= 5'b0;
            p <= 16'b0;
            rdy <= 1'b0;
        end else begin
            if (ctr < 5'd16) begin
                multiplicand <= multiplicand << 1;

                if (multiplier[ctr] == 1'b1) begin
                    p <= p + multiplicand;
                end

                ctr <= ctr + 1;
            end else begin
                rdy <= 1'b1;
            end
        end
    end

endmodule

module barrel_shifter (
    input [7:0] in,
    input [2:0] ctrl,
    output [7:0] out
);
    wire [7:0] mux_4_out;
    wire [7:0] mux_2_out;
    wire [7:0] mux_1_out;

    mux2X1 #(8) mux_4 (
        .in0(in),
        .in1({in[3:0], in[7:4]}),
        .sel(ctrl[2]),
        .out(mux_4_out)
    );

    mux2X1 #(8) mux_2 (
        .in0(mux_4_out),
        .in1({mux_4_out[5:0], mux_4_out[7:6]}),
        .sel(ctrl[1]),
        .out(mux_2_out)
    );

    mux2X1 #(8) mux_1 (
        .in0(mux_2_out),
        .in1({mux_2_out[6:0], mux_2_out[7]}),
        .sel(ctrl[0]),
        .out(mux_1_out)
    );

    assign out = mux_1_out;
endmodule

module mux2X1( in0,in1,sel,out);
input in0,in1;
input sel;
output out;
assign out=(sel)?in1:in0;
endmodule

module radix2_div (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

    reg [7:0] dividend_abs, divisor_abs;
    reg [15:0] SR;
    reg [7:0] NEG_DIVISOR;
    reg [3:0] cnt;
    reg start_cnt;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 1'b0;
            cnt <= 4'b0;
            start_cnt <= 1'b0;
        end
        else if (opn_valid && !res_valid) begin
            dividend_abs <= sign ? (dividend[7] ? -dividend : dividend) : dividend;
            divisor_abs <= sign ? (divisor[7] ? -divisor : divisor) : divisor;
            NEG_DIVISOR <= {1'b0, divisor_abs[7:1]};
            SR <= {dividend_abs, 1'b0};
            cnt <= 4'b0001;
            start_cnt <= 1'b1;
        end
        else if (start_cnt) begin
            if (cnt[3]) begin
                start_cnt <= 1'b0;
                res_valid <= 1'b1;
                result <= SR;
            end
            else begin
                cnt <= cnt + 4'b0001;
                {SR, NEG_DIVISOR} <= {SR[15:0], NEG_DIVISOR[7:1]};
            end
        end
        else if (res_valid && res_ready) begin
            res_valid <= 1'b0;
        end
    end

endmodule

