module fixed_point_subtractor #(
	parameter Q = 15,
	parameter N = 32
	)
	(
    input [N-1:0] a,
    input [N-1:0] b,
    output [N-1:0] c
    );

reg [N-1:0] res;

assign c = res;

always @(a,b) begin

	if(a[N-1] == b[N-1]) begin					
		res[N-2:0] = a[N-2:0] - b[N-2:0];		
		res[N-1] = a[N-1];							


		end												

	else if(a[N-1] == 0 && b[N-1] == 1) begin		
		if( a[N-2:0] > b[N-2:0] ) begin					
			res[N-2:0] = a[N-2:0] + b[N-2:0];			
			res[N-1] = 0;										
			end
		else begin												
			res[N-2:0] = b[N-2:0] + a[N-2:0];		
			if (res[N-2:0] == 0)
				res[N-1] = 0;									
			else
				res[N-1] = 1;									
			end
		end
	else begin												
		if( a[N-2:0] > b[N-2:0] ) begin					
			res[N-2:0] = a[N-2:0] + b[N-2:0];			
			if (res[N-2:0] == 0)
				res[N-1] = 0;										
			else
				res[N-1] = 1;										
			end
		else begin												
			res[N-2:0] = b[N-2:0] + a[N-2:0];			
			res[N-1] = 0;										
			end
		end
	end
endmodule

module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);
    reg [2:0] state, next_state;
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            state <= s0;
            MATCH <= 1'b0;
        end
        else begin
            state <= next_state;
        end
    end
    always @(*) begin
        case (state)
            s0: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s0;
                end
                MATCH = 1'b0;
            end
            s1: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s2;
                end
                MATCH = 1'b0;
            end
            s2: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s3;
                end
                MATCH = 1'b0;
            end
            s3: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s4;
                end
                MATCH = 1'b0;
            end
            s4: begin
                if (IN) begin
                    next_state = s5;
                end
                else begin
                    next_state = s0;
                end
                MATCH = 1'b0;
            end
            s5: begin
                if (IN) begin
                    next_state = s1;
                end
                else begin
                    next_state = s2;
                end
                MATCH = 1'b0;
            end
            default: begin
                next_state = s0;
                MATCH = 1'b0;
            end
        endcase
    end
endmodule

module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

reg [3:0] cnt_10;
reg [6:0] cnt_100;

always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        CLK_50 <= 1'b0;
        CLK_10 <= 1'b0;
        CLK_1 <= 1'b0;
        cnt_10 <= 4'b0;
        cnt_100 <= 7'b0;
    end
    else begin

        CLK_50 <= ~CLK_50;

        if (cnt_10 == 4'd4) begin
            CLK_10 <= ~CLK_10;
            cnt_10 <= 4'b0;
        end
        else begin
            cnt_10 <= cnt_10 + 4'b1;
        end

        if (cnt_100 == 7'd49) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 7'b0;
        end
        else begin
            cnt_100 <= cnt_100 + 7'b1;
        end
    end
end

endmodule

module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter JR = 6'b001000,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);
reg [32:0] RES;
wire [31:0] a_signed, b_signed;
assign a_signed = a;
assign b_signed = b;
assign r = RES[31:0];
assign zero = &RES[31:0];
assign negative = RES[31];
assign flag = aluc == SLT || aluc == SLTU;
always @(*) begin
    case (aluc)
        ADD: {carry, RES} = a_signed + b_signed;
        ADDU: {carry, RES} = a + b;
        SUB: {carry, RES} = a_signed - b_signed;
        SUBU: {carry, RES} = a - b;
        AND: RES = {1'b0, a & b};
        OR: RES = {1'b0, a | b};
        XOR: RES = {1'b0, a ^ b};
        NOR: RES = {1'b0, ~(a | b)};
        SLT: RES = {1'b0, a_signed < b_signed};
        SLTU: RES = {1'b0, a < b};
        SLL: RES = {1'b0, b << a[4:0]};
        SRL: RES = {1'b0, b >> a[4:0]};
        SRA: RES = {1'b0, b_signed >>> a[4:0]};
        SLLV: RES = {1'b0, b << a[4:0]};
        SRLV: RES = {1'b0, b >> a[4:0]};
        SRAV: RES = {1'b0, b_signed >>> a[4:0]};
        LUI: RES = {b[15:0], 16'b0};
        default: RES = 33'b0;
    endcase
    overflow = (aluc == ADD || aluc == SUB) && ((a_signed[31] == b_signed[31]) && (a_signed[31] != RES[31]));
end
endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
); 
    reg a_dly;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            a_dly <= 1'b0;
            rise <= 1'b0;
