module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [WIDTH-1:0] ram [DEPTH-1:0];
reg [ADDR_WIDTH-1:0] wptr, rptr;
always @(posedge wclk) begin
    if (winc && !wfull)
        ram[wptr] <= wdata;
end
always @(posedge rclk) begin
    if (rinc && !rempty)
        rdata <= ram[rptr];
end

reg [ADDR_WIDTH:0] wgray, wbin;
wire [ADDR_WIDTH:0] wgraynext, wbinnext;
assign wgraynext = wbinnext ^ (wbinnext >> 1);
assign wbinnext = wbin + { {(ADDR_WIDTH){1'b0}}, winc};
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) wbin <= { {(ADDR_WIDTH){1'b0}}, 1'b1}; else wbin <= wbinnext;
end
assign wgray = wbin ^ (wbin >> 1);
assign wfull = (wgray == {~wgray[ADDR_WIDTH:ADDR_WIDTH-1], wgray[ADDR_WIDTH-2:0]});

reg [ADDR_WIDTH:0] rgray, rbin;
wire [ADDR_WIDTH:0] rgraynext, rbinnext;
assign rgraynext = rbinnext ^ (rbinnext >> 1);
assign rbinnext = rbin + { {(ADDR_WIDTH){1'b0}}, rinc};
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) rbin <= { {(ADDR_WIDTH){1'b0}}, 1'b1}; else rbin <= rbinnext;
end
assign rgray = rbin ^ (rbin >> 1);
assign rempty = (rgray == wgray);

endmodule

