    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
); 

    reg [1:0] state, next_state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= s0;
        end else begin
            state <= next_state;
        end
    end

    always @(*) begin
        case(state)
            s0: begin
                if(data_in == 1'b0) begin
                    next_state = s1;
                end else begin
                    next_state = s0;
                end
            end

            s1: begin
                if(data_in == 1'b1) begin
                    next_state = s2;
                end else begin
                    next_state = s1;
                end
            end

            s2: begin
                if(data_in == 1'b0) begin
                    next_state = s3;
                end else begin
                    next_state = s0;
                end
            end

            s3: begin
                if(data_in == 1'b1) begin
                    next_state = s2;
                end else begin
                    next_state = s1;
                end
            end

            default: next_state = s0;
        endcase
    end

    always @(*) begin
        case(state)
            s0: data_out = 1'b0;
            s1: data_out = 1'b0;
            s2: data_out = 1'b1;
            s3: data_out = 1'b0;
            default: data_out = 1'b0;
        endcase
    end
endmodule

