module comparator_4bit (
    input [3:0] A,
    input [3:0] B,
    output reg A_greater,
    output reg A_equal,
    output reg A_less
);

    wire [3:0] diff;
    wire carry;

    assign {carry, diff} = A - B;

    always @(*) begin
        if (carry) begin
            A_greater = 1'b0;
            A_equal = 1'b0;
            A_less = 1'b1;
        end
        else if (diff == 4'b0000) begin
            A_greater = 1'b0;
            A_equal = 1'b1;
            A_less = 1'b0;
        end
        else begin
            A_greater = 1'b1;
            A_equal = 1'b0;
            A_less = 1'b0;
        end
    end

endmodule

module ring_counter (
    input wire clk,
    input wire reset,
    output reg [7:0] out
);

always @(posedge clk or posedge (reset)) begin
    if (reset) begin
        out <= 8'b0000_0001;
    end else begin
        out <= {out[6:0], out[7]};
    end
end

endmodule

module adder_8bit (
    input [7:0] a,
    b,
    input cin,
    output [7:0] sum,
    output cout
);

    wire [7:0] carry;

    assign {carry[0], sum[0]} = a[0] + b[0] + cin;
    assign {carry[1], sum[1]} = a[1] + b[1] + carry[0];
    assign {carry[2], sum[2]} = a[2] + b[2] + carry[1];
    assign {carry[3], sum[3]} = a[3] + b[3] + carry[2];
    assign {carry[4], sum[4]} = a[4] + b[4] + carry[3];
    assign {carry[5], sum[5]} = a[5] + b[5] + carry[4];
    assign {carry[6], sum[6]} = a[6] + b[6] + carry[5];
    assign {cout, sum[7]} = a[7] + b[7] + carry[6];

endmodule

module full_adder (input a, b, cin, output sum, cout);
    assign {cout, sum} = a + b + cin;
endmodule

module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);
    reg [7:0] data_buf [3:0];
    reg [1:0] cnt;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 0;
            valid_out <= 0;
            data_out <= 0;
        end else if (valid_in) begin
            data_buf[cnt] <= data_in;
            cnt <= cnt + 1;
            if (cnt == 2'd3) begin
                data_out <= {2'b00, data_buf[0]} + {2'b00, data_buf[1]} + {2'b00, data_buf[2]} + {2'b00, data_buf[3]};
                valid_out <= 1;
                cnt <= 0;
            end else begin
                valid_out <= 0;
            end
        end else begin
            valid_out <= 0;
        end
    end
endmodule

module freq_divbyeven #(
    parameter NUM_DIV = 6
) (
    input clk,
    input rst_n,
    output reg clk_div
);

    reg [3:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'b0;
            clk_div <= 1'b0;
        end
        else begin
            if (cnt == (NUM_DIV/2 - 1)) begin
                cnt <= 4'b0;
                clk_div <= ~clk_div;
            end
            else begin
                cnt <= cnt + 1'b1;
            end
        end
    end

endmodule

module LFSR (
    output reg [3:0] out,
    input clk,
    input rst
);

    wire feedback;

    assign feedback = ~(out[3] ^ out[2]);

    always @(posedge clk) begin
        if (rst) begin
            out <= 4'b0000;
        end else begin
            out <= {out[2:0], feedback};
        end
    end

endmodule

module freq_divbyodd #(
    parameter NUM_DIV = 5
) (
    input clk,
    input rst_n,
    output reg clk_div
);
parameter HALF_DIV = NUM_DIV / 2;
parameter COUNTER_MAX = NUM_DIV - 1;

reg [3:0] cnt1, cnt2;
reg clk_div1, clk_div2;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt1 <= 0;
        clk_div1 <= 0;
    end else begin
        if (cnt1 == COUNTER_MAX) begin
            cnt1 <= 0;
            clk_div1 <= ~clk_div1;
        end else begin
            cnt1 <= cnt1 + 1;
        end
    end
end

always @(negedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt2 <= 0;
        clk_div2 <= 0;
    end else begin
        if (cnt2 == COUNTER_MAX) begin
            cnt2 <= 0;
            clk_div2 <= ~clk_div2;
        end else begin
            cnt2 <= cnt2 + 1;
        end
    end
end

always @(*) begin
    clk_div = clk_div1 | clk_div2;
end

endmodule

